/**
 * Options for observation normalization.
 */
export interface NormalizationOptions {
  /** Resolve pronouns to entity names */
  resolveCoreferences?: boolean;
  /** Convert relative dates to absolute dates */
  anchorTimestamps?: boolean;
  /** Extract and tag keywords */
  extractKeywords?: boolean;
  /** Reference date for relative date conversion (default: now) */
  referenceDate?: Date;
}

/**
 * Result of normalizing an observation.
 */
export interface NormalizationResult {
  original: string;
  normalized: string;
  changes: string[];
  keywords?: string[];
}

/**
 * Observation Normalizer transforms observations to self-contained facts.
 *
 * Applies transformations:
 * 1. Coreference resolution: 'He works' -> 'Alice works'
 * 2. Temporal anchoring: 'yesterday' -> '2026-01-07'
 * 3. Keyword extraction: Identifies important terms
 *
 * @example
 * ```typescript
 * const normalizer = new ObservationNormalizer();
 * const result = normalizer.normalize(
 *   'He started the project yesterday',
 *   { name: 'Bob', entityType: 'person', observations: [] }
 * );
 * // result.normalized = 'Bob started the project on 2026-01-07'
 * ```
 */
export class ObservationNormalizer {
  private pronounPatterns = {
    masculine: /\b(he|him|his)\b/gi,
    feminine: /\b(she|her|hers)\b/gi,
    neutral: /\b(they|them|their|theirs)\b/gi,
  };

  private relativeTimePatterns: [RegExp, (ref: Date) => string][] = [
    [/\byesterday\b/i, (ref) => this.formatDate(this.addDays(ref, -1))],
    [/\btoday\b/i, (ref) => this.formatDate(ref)],
    [/\btomorrow\b/i, (ref) => this.formatDate(this.addDays(ref, 1))],
    [/\blast week\b/i, (ref) => `week of ${this.formatDate(this.addDays(ref, -7))}`],
    [/\blast month\b/i, (ref) => this.formatMonth(this.addMonths(ref, -1))],
    [/\blast year\b/i, (ref) => `${ref.getFullYear() - 1}`],
    [/\bthis week\b/i, (ref) => `week of ${this.formatDate(ref)}`],
    [/\bthis month\b/i, (ref) => this.formatMonth(ref)],
    [/\bthis year\b/i, (ref) => `${ref.getFullYear()}`],
  ];

  /**
   * Normalize an observation for an entity.
   */
  normalize(
    observation: string,
    entity: Entity,
    options: NormalizationOptions = {}
  ): NormalizationResult {
    const {
      resolveCoreferences = true,
      anchorTimestamps = true,
      extractKeywords = false,
      referenceDate = new Date(),
    } = options;

    let normalized = observation;
    const changes: string[] = [];

    if (resolveCoreferences) {
      const corefResult = this.resolveCoreferences(normalized, entity);
      if (corefResult.changed) {
        normalized = corefResult.text;
        changes.push(`Resolved pronouns to '${entity.name}'`);
      }
    }

    if (anchorTimestamps) {
      const timeResult = this.anchorTimestamps(normalized, referenceDate);
      if (timeResult.changed) {
        normalized = timeResult.text;
        changes.push(...timeResult.replacements);
      }
    }

    const keywords = extractKeywords
      ? this.extractKeywords(normalized)
      : undefined;

    return {
      original: observation,
      normalized,
      changes,
      keywords,
    };
  }

/**
 * Resolve pronouns to entity name.
 */
resolveCoreferences(
  text: string,
  entity: Entity
): { text: string; changed: boolean } {
  let result = text;
  let changed = false;

  // Determine gender hint from entity type or name patterns
  const isMasculine = this.guessMasculine(entity);
  const isFeminine = this.guessFeminine(entity);

  // Replace pronouns based on detected gender
  if (isMasculine) {
    const newText = result
      .replace(this.pronounPatterns.masculine, entity.name);
    if (newText !== result) {
      result = newText;
      changed = true;
    }
  } else if (isFeminine) {
    const newText = result
      .replace(this.pronounPatterns.feminine, entity.name);
    if (newText !== result) {
      result = newText;
      changed = true;
    }
  }

  // Always try neutral pronouns for non-person entities
  if (entity.entityType.toLowerCase() !== 'person') {
    const newText = result
      .replace(this.pronounPatterns.neutral, entity.name);
    if (newText !== result) {
      result = newText;
      changed = true;
    }
  }

  return { text: result, changed };
}

private guessMasculine(entity: Entity): boolean {
  const masculineNames = ['john', 'james', 'bob', 'mike', 'david', 'alex'];
  return masculineNames.some(n => entity.name.toLowerCase().includes(n));
}

private guessFeminine(entity: Entity): boolean {
  const feminineNames = ['alice', 'jane', 'sarah', 'mary', 'emma', 'lisa'];
  return feminineNames.some(n => entity.name.toLowerCase().includes(n));
}

/**
 * Convert relative timestamps to absolute dates.
 */
anchorTimestamps(
  text: string,
  referenceDate: Date
): { text: string; changed: boolean; replacements: string[] } {
  let result = text;
  const replacements: string[] = [];

  for (const [pattern, resolver] of this.relativeTimePatterns) {
    const match = result.match(pattern);
    if (match) {
      const replacement = resolver(referenceDate);
      result = result.replace(pattern, replacement);
      replacements.push(`'${match[0]}' -> '${replacement}'`);
    }
  }

  return {
    text: result,
    changed: replacements.length > 0,
    replacements,
  };
}

private addDays(date: Date, days: number): Date {
  const result = new Date(date);
  result.setDate(result.getDate() + days);
  return result;
}

private addMonths(date: Date, months: number): Date {
  const result = new Date(date);
  result.setMonth(result.getMonth() + months);
  return result;
}

private formatDate(date: Date): string {
  return date.toISOString().split('T')[0];
}

private formatMonth(date: Date): string {
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
}

  /**
   * Extract important keywords from text.
   */
  extractKeywords(text: string): string[] {
    const stopwords = new Set([
      'a', 'an', 'the', 'is', 'are', 'was', 'were', 'be', 'been',
      'being', 'have', 'has', 'had', 'do', 'does', 'did', 'will',
      'would', 'could', 'should', 'may', 'might', 'must', 'shall',
      'can', 'to', 'of', 'in', 'for', 'on', 'with', 'at', 'by',
      'from', 'as', 'into', 'through', 'during', 'before', 'after',
      'above', 'below', 'between', 'under', 'again', 'further',
      'then', 'once', 'here', 'there', 'when', 'where', 'why', 'how',
      'all', 'each', 'few', 'more', 'most', 'other', 'some', 'such',
      'no', 'nor', 'not', 'only', 'own', 'same', 'so', 'than', 'too',
      'very', 's', 't', 'just', 'don', 'now', 'and', 'but', 'or',
    ]);

    const words = text
      .toLowerCase()
      .replace(/[^a-z0-9\s]/g, '')
      .split(/\s+/)
      .filter(w => w.length > 2 && !stopwords.has(w));

    // Return unique keywords
    return [...new Set(words)];
  }

  /**
   * Normalize all observations for an entity.
   */
  normalizeEntity(
    entity: Entity,
    options: NormalizationOptions = {}
  ): { entity: Entity; results: NormalizationResult[] } {
    const results = entity.observations.map(obs =>
      this.normalize(obs, entity, options)
    );

    return {
      entity: {
        ...entity,
        observations: results.map(r => r.normalized),
      },
      results,
    };
  }
}

/**
 * Keyword Extractor
 *
 * Phase 11: Extracts and scores keywords from text
 * for lexical search enhancement.
 *
 * @module features/KeywordExtractor
 */

/**
 * A keyword with importance score.
 */
export interface ScoredKeyword {
  keyword: string;
  score: number;
  positions: number[];
}

/**
 * Keyword Extractor extracts and scores keywords from text.
 */
export class KeywordExtractor {
  private stopwords: Set<string>;
  private domainBoosts: Map<string, number>;

  constructor() {
    this.stopwords = new Set([
      'a', 'an', 'the', 'is', 'are', 'was', 'were', 'be', 'been',
      'have', 'has', 'had', 'do', 'does', 'did', 'will', 'would',
      'could', 'should', 'can', 'to', 'of', 'in', 'for', 'on',
      'with', 'at', 'by', 'from', 'as', 'and', 'or', 'but',
    ]);
    this.domainBoosts = new Map([
      ['project', 1.5],
      ['task', 1.5],
      ['meeting', 1.3],
      ['deadline', 1.4],
      ['completed', 1.2],
      ['started', 1.2],
    ]);
  }

  /**
   * Extract keywords with scores from text.
   */
  extract(text: string): ScoredKeyword[] {
    const words = this.tokenize(text);
    const keywordMap = new Map<string, ScoredKeyword>();

    for (let i = 0; i < words.length; i++) {
      const word = words[i].toLowerCase();
      if (this.isKeyword(word)) {
        const existing = keywordMap.get(word);
        if (existing) {
          existing.positions.push(i);
          existing.score += this.calculateScore(word, i, words.length);
        } else {
          keywordMap.set(word, {
            keyword: word,
            score: this.calculateScore(word, i, words.length),
            positions: [i],
          });
        }
      }
    }

    return Array.from(keywordMap.values())
      .sort((a, b) => b.score - a.score);
  }

  private tokenize(text: string): string[] {
    return text
      .replace(/[^a-zA-Z0-9\s]/g, ' ')
      .split(/\s+/)
      .filter(w => w.length > 0);
  }

  private isKeyword(word: string): boolean {
    return word.length > 2 && !this.stopwords.has(word);
  }

  private calculateScore(word: string, position: number, totalWords: number): number {
    let score = 1.0;

    // Position boost (earlier = more important)
    const positionFactor = 1 - (position / totalWords) * 0.3;
    score *= positionFactor;

    // Domain boost
    const boost = this.domainBoosts.get(word) ?? 1.0;
    score *= boost;

    // Length boost (longer words often more specific)
    if (word.length > 6) score *= 1.1;

    return score;
  }

  /**
   * Extract top N keywords.
   */
  extractTop(text: string, n: number): string[] {
    return this.extract(text)
      .slice(0, n)
      .map(k => k.keyword);
  }
}

{
  name: 'normalize_observations',
  description: 'Normalize entity observations by resolving pronouns and anchoring relative dates. Improves search matching quality.',
  inputSchema: {
    type: 'object',
    properties: {
      entityName: {
        type: 'string',
        description: 'Entity name to normalize (omit for all entities)',
      },
      options: {
        type: 'object',
        properties: {
          resolveCoreferences: { type: 'boolean', default: true },
          anchorTimestamps: { type: 'boolean', default: true },
          extractKeywords: { type: 'boolean', default: false },
        },
      },
      persist: {
        type: 'boolean',
        default: false,
        description: 'Save normalized observations to storage',
      },
    },
    required: [],
  },
},

import { ObservationNormalizer } from '../features/ObservationNormalizer.js';

// In switch statement:
case 'normalize_observations': {
  const { entityName, options = {}, persist = false } = args;

  const normalizer = new ObservationNormalizer();
  const graph = await ctx.storage.loadGraph();

  const entities = entityName
    ? graph.entities.filter(e => e.name === entityName)
    : graph.entities;

  const results = entities.map(entity => {
    const { entity: normalized, results: changes } = normalizer.normalizeEntity(entity, options);
    return {
      entityName: entity.name,
      changes: changes.filter(r => r.changes.length > 0),
      normalized: normalized.observations,
    };
  });

  if (persist) {
    // Update entities with normalized observations
    for (const result of results) {
      const entity = graph.entities.find(e => e.name === result.entityName);
      if (entity) {
        entity.observations = result.normalized;
        entity.lastModified = new Date().toISOString();
      }
    }
    await ctx.storage.saveGraph(graph);
  }

  return {
    content: [{
      type: 'text',
      text: JSON.stringify({
        entitiesProcessed: results.length,
        persisted: persist,
        results: results.filter(r => r.changes.length > 0),
      }, null, 2),
    }],
  };
}

import { describe, it, expect, beforeEach } from 'vitest';
import { ObservationNormalizer } from '../../../src/features/ObservationNormalizer.js';
import { KeywordExtractor } from '../../../src/features/KeywordExtractor.js';
import type { Entity } from '../../../src/types/index.js';

describe('ObservationNormalizer', () => {
  let normalizer: ObservationNormalizer;

  beforeEach(() => {
    normalizer = new ObservationNormalizer();
  });

  describe('coreference resolution', () => {
    it('should resolve masculine pronouns', () => {
      const entity: Entity = { name: 'Bob', entityType: 'person', observations: [] };
      const result = normalizer.normalize('He started the project', entity);
      expect(result.normalized).toContain('Bob');
    });

    it('should resolve feminine pronouns', () => {
      const entity: Entity = { name: 'Alice', entityType: 'person', observations: [] };
      const result = normalizer.normalize('She completed the task', entity);
      expect(result.normalized).toContain('Alice');
    });
  });

  describe('timestamp anchoring', () => {
    it('should anchor yesterday', () => {
      const entity: Entity = { name: 'Test', entityType: 'event', observations: [] };
      const result = normalizer.normalize('Meeting happened yesterday', entity, {
        referenceDate: new Date('2026-01-08'),
      });
      expect(result.normalized).toContain('2026-01-07');
    });

    it('should anchor last month', () => {
      const entity: Entity = { name: 'Test', entityType: 'event', observations: [] };
      const result = normalizer.normalize('Started last month', entity, {
        referenceDate: new Date('2026-01-08'),
      });
      expect(result.normalized).toContain('2025-12');
    });
  });
});

describe('KeywordExtractor', () => {
  let extractor: KeywordExtractor;

  beforeEach(() => {
    extractor = new KeywordExtractor();
  });

  it('should extract keywords from text', () => {
    const keywords = extractor.extract('The software project was completed on time');
    expect(keywords.map(k => k.keyword)).toContain('software');
    expect(keywords.map(k => k.keyword)).toContain('project');
  });

  it('should score domain keywords higher', () => {
    const keywords = extractor.extract('The project meeting was productive');
    const projectKw = keywords.find(k => k.keyword === 'project');
    const productiveKw = keywords.find(k => k.keyword === 'productive');
    expect(projectKw!.score).toBeGreaterThan(productiveKw!.score);
  });
});
